    int numWays(int steps, int arrLen) {
        const int MOD = 1e9 + 7;
        vector<vector<int>> dp(steps + 1, vector<int>(steps + 1, 0));
        dp[0][0] = 1;
        for (int i = 1; i <= steps; i++) {
            for (int j = 0; j <= min(i, arrLen - 1); j++) {
                dp[i][j] = (dp[i - 1][j] + dp[i - 1][j - 1] + dp[i - 1][j + 1]) % MOD;
            }
        }
        return dp[steps][0];
    }
};
